class Solution(object):
    def distinctPoints(self, s, k):
        n = len(s)
        # Compute prefix sums for x and y
        dx = {'R': 1, 'L': -1, 'U': 0, 'D': 0}
        dy = {'U': 1, 'D': -1, 'L': 0, 'R': 0}
        px = [0] * (n + 1)
        py = [0] * (n + 1)
        for i, c in enumerate(s):
            px[i+1] = px[i] + dx[c]
            py[i+1] = py[i] + dy[c]
        # Removing substring s[l..l+k-1] (0-indexed)
        # Final x = px[l] + (px[n] - px[l+k]) = px[l] - px[l+k] + px[n]
        # Final y similarly
        # Distinct points = |{(px[l] - px[l+k], py[l] - py[l+k]) : 0 <= l <= n-k}|
        points = set()
        total_x = px[n]
        total_y = py[n]
        for l in range(n - k + 1):
            x = px[l] - px[l + k] + total_x
            y = py[l] - py[l + k] + total_y
            points.add((x, y))
        return len(points)
